import{_ as a,c as e,o as s,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"アカウント移行: バックアップ/ホットマイグレーション | Antigravity Manager","description":"Antigravity Manager のアカウントバックアップと移行を学びます。JSON インポート/エクスポート、Antigravity/IDE からのホットマイグレーション、V1 データディレクトリからの移行、現在ログイン中のアカウントの自動同期をサポート。","frontmatter":{"title":"アカウント移行: バックアップ/ホットマイグレーション | Antigravity Manager","sidebarTitle":"3 分でアカウントプールを移行","subtitle":"アカウント移行: バックアップ/ホットマイグレーション","description":"Antigravity Manager のアカウントバックアップと移行を学びます。JSON インポート/エクスポート、Antigravity/IDE からのホットマイグレーション、V1 データディレクトリからの移行、現在ログイン中のアカウントの自動同期をサポート。","tags":["アカウント管理","バックアップ","移行","インポート/エクスポート","state.vscdb"],"prerequisite":["start-add-account","start-first-run-data"],"duration":12,"order":5},"headers":[],"relativePath":"ja/lbjlaq/Antigravity-Manager/start/backup-migrate/index.md","filePath":"ja/lbjlaq/Antigravity-Manager/start/backup-migrate/index.md"}'),r={name:"ja/lbjlaq/Antigravity-Manager/start/backup-migrate/index.md"};function o(n,t,l,d,c,h){return s(),e("div",null,[...t[0]||(t[0]=[i(`<h1 id="アカウントバックアップと移行-インポート-エクスポート、v1-db-ホットマイグレーション" tabindex="-1">アカウントバックアップと移行：インポート/エクスポート、V1/DB ホットマイグレーション <a class="header-anchor" href="#アカウントバックアップと移行-インポート-エクスポート、v1-db-ホットマイグレーション" aria-label="Permalink to &quot;アカウントバックアップと移行：インポート/エクスポート、V1/DB ホットマイグレーション&quot;">​</a></h1><p>あなたが実際に「バックアップ」したいのは、クォータ数字ではなく、アカウントを再度ログインさせることができる <code>refresh_token</code> です。このレッスンでは、Antigravity Tools の複数の移行方法を明確に説明します：JSON インポート/エクスポート、<code>state.vscdb</code> からのインポート、V1 データディレクトリからのインポート、自動同期の動作方法。</p><h2 id="学習後にできること" tabindex="-1">学習後にできること <a class="header-anchor" href="#学習後にできること" aria-label="Permalink to &quot;学習後にできること&quot;">​</a></h2><ul><li>アカウントプールを JSON ファイルとしてエクスポートする（email + refresh_token のみ含む）</li><li>新しいマシンでこの JSON をインポートし、アカウントプールを迅速に復元する</li><li>Antigravity/IDE の <code>state.vscdb</code> から「現在ログイン中のアカウント」を直接インポートする（デフォルトパスとカスタムパスをサポート）</li><li>V1 データディレクトリから自動的にスキャンし、古いアカウントをインポートする</li><li>「現在アカウントの自動同期」が実際に何をするか、いつスキップされるかを理解する</li></ul><h2 id="現在の課題" tabindex="-1">現在の課題 <a class="header-anchor" href="#現在の課題" aria-label="Permalink to &quot;現在の課題&quot;">​</a></h2><ul><li>システム再インストール/マシン変更後、アカウントプールを再度追加する必要があり、コストが高い</li><li>Antigravity/IDE でログインアカウントを切り替えたが、Manager 内の「現在のアカウント」が変更されていない</li><li>以前 V1/スクリプト版を使用しており、古いデータファイルしか持っておらず、直接移行できるかわからない</li></ul><h2 id="いつこの方法を使用するか" tabindex="-1">いつこの方法を使用するか <a class="header-anchor" href="#いつこの方法を使用するか" aria-label="Permalink to &quot;いつこの方法を使用するか&quot;">​</a></h2><ul><li>アカウントプールを別のマシン（デスクトップ/サーバー/コンテナ）に移動したい場合</li><li>Antigravity を「権威あるログイン入口」とし、Manager が現在のアカウントを自動的に同期してほしい場合</li><li>旧バージョン（V1 データディレクトリ）からアカウントを移動したい場合</li></ul><h2 id="🎒-開始前の準備" tabindex="-1">🎒 開始前の準備 <a class="header-anchor" href="#🎒-開始前の準備" aria-label="Permalink to &quot;🎒 開始前の準備&quot;">​</a></h2><ul><li>Antigravity Tools を開くことができ、アカウントプールに少なくとも 1 つのアカウントがある</li><li>アカウントデータが機密情報であることを知っている（特に <code>refresh_token</code>）</li></ul><div class="warning custom-block"><p class="custom-block-title">セキュリティ提醒：バックアップファイルをパスワードとして扱う</p><p>エクスポートされた JSON ファイルには <code>refresh_token</code> が含まれています。これを入手した人は誰でも、それを使用して access token を更新できる可能性があります。バックアップファイルをクラウドストレージのパブリックリンクにアップロードしたり、グループに送信したり、Git にコミットしたりしないでください。</p></div><h2 id="コアアイデア" tabindex="-1">コアアイデア <a class="header-anchor" href="#コアアイデア" aria-label="Permalink to &quot;コアアイデア&quot;">​</a></h2><p>Antigravity Tools の「移行」は本質的に2つのことです：</p><ol><li>使用可能な <code>refresh_token</code> を見つける</li><li>それを使用して access token を取得し、Google から実際のメールアドレスを取得し、アカウントをローカルアカウントプールに書き込む</li></ol><p>3 つのエントリを提供します：</p><ul><li>JSON インポート/エクスポート：「制御可能なバックアップ」を明確に行いたい場合に適している</li><li>DB インポート：Antigravity/IDE のログイン状態を権威あるソースとみなす場合に適している（デフォルトで <code>state.vscdb</code> を検索し、手動ファイル選択もサポート）</li><li>V1 インポート：古いデータディレクトリから自動的にスキャンし、移行する場合に適している</li></ul><p>さらに「自動同期」があります：DB 内の refresh_token を定期的に読み取り、Manager の現在のアカウントと異なる場合、自動的に DB インポートを実行します。同じ場合はスキップします（トラフィックを節約）。</p><h2 id="手順に従って進める" tabindex="-1">手順に従って進める <a class="header-anchor" href="#手順に従って進める" aria-label="Permalink to &quot;手順に従って進める&quot;">​</a></h2><h3 id="ステップ-1-アカウントプールをエクスポートする-json-バックアップ" tabindex="-1">ステップ 1：アカウントプールをエクスポートする（JSON バックアップ） <a class="header-anchor" href="#ステップ-1-アカウントプールをエクスポートする-json-バックアップ" aria-label="Permalink to &quot;ステップ 1：アカウントプールをエクスポートする（JSON バックアップ）&quot;">​</a></h3><p><strong>なぜ</strong> これが最も安定した、制御可能な移行方法です。ファイルを 1 つ入手するだけで、別のマシンでアカウントプールを復元できます。</p><p>操作：<code>Accounts</code> ページに入り、エクスポートボタンをクリックします。</p><ul><li>設定で <code>default_export_path</code> を設定している場合、エクスポートは直接そのディレクトリに書き込まれ、ファイル名は <code>antigravity_accounts_YYYY-MM-DD.json</code> になります。</li><li>デフォルトディレクトリを設定していない場合、システム保存ダイアログが表示され、パスを選択できます。</li></ul><p>エクスポートファイルの内容は次のようになります（配列内の各項目は必要なフィールドのみ保持）：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;email&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;alice@example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;refresh_token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1//xxxxxxxxxxxxxxxxxxxxxxxx&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;email&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bob@example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;refresh_token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1//yyyyyyyyyyyyyyyyyyyyyyyy&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p><strong>次のように表示されます</strong>：ページでエクスポート成功が通知され、保存パスが表示されます。</p><h3 id="ステップ-2-新しいマシンで-json-をインポートする-アカウントプールを復元" tabindex="-1">ステップ 2：新しいマシンで JSON をインポートする（アカウントプールを復元） <a class="header-anchor" href="#ステップ-2-新しいマシンで-json-をインポートする-アカウントプールを復元" aria-label="Permalink to &quot;ステップ 2：新しいマシンで JSON をインポートする（アカウントプールを復元）&quot;">​</a></h3><p><strong>なぜ</strong> インポートは「アカウント追加」ロジックを個別に呼び出し、<code>refresh_token</code> を使用して実際のメールアドレスを取得し、アカウントプールに書き込みます。</p><p>操作：引き続き <code>Accounts</code> ページで、「Import JSON」をクリックし、エクスポートしたファイルを選択します。</p><p>形式要件は次のとおりです（少なくとも 1 つの有効なレコードを含む必要があります）：</p><ul><li>JSON 配列である必要があります</li><li><code>refresh_token</code> を含み、<code>1//</code> で始まる項目のみがインポートされます</li></ul><p><strong>次のように表示されます</strong>：インポート完了後、アカウントリストにインポートされたアカウントが表示されます。</p><div class="tip custom-block"><p class="custom-block-title">Proxy を実行中にインポートする場合</p><p>「アカウント追加」が成功するたびに、バックエンドはリバースプロキシのトークンプールのリロードを試み、新しいアカウントを即座に有効にします。</p></div><h3 id="ステップ-3-state-vscdb-から「現在ログイン中のアカウント」をインポートする" tabindex="-1">ステップ 3：<code>state.vscdb</code> から「現在ログイン中のアカウント」をインポートする <a class="header-anchor" href="#ステップ-3-state-vscdb-から「現在ログイン中のアカウント」をインポートする" aria-label="Permalink to &quot;ステップ 3：\`state.vscdb\` から「現在ログイン中のアカウント」をインポートする&quot;">​</a></h3><p><strong>なぜ</strong> バックアップファイルを管理したくなく、「Antigravity/IDE のログイン状態を基準にしたい」だけの場合があります。DB インポートはこのシナリオ用です。</p><p>操作：<code>Accounts</code> ページに入り、<strong>Add Account</strong> をクリックし、<code>Import</code> タブに切り替えます：</p><ul><li>「Import from Database」をクリック（デフォルト DB パスを使用）</li><li>または「Custom DB (state.vscdb)」をクリックし、<code>*.vscdb</code> ファイルを手動で選択</li></ul><p>デフォルトの DB パスはクロスプラットフォームです（<code>--user-data-dir</code> または portable mode も優先的に識別されます）：</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-HuPdO" id="tab-YuRPoDg" checked><label data-title="macOS" for="tab-YuRPoDg">macOS</label><input type="radio" name="group-HuPdO" id="tab-crRq0Rs"><label data-title="Windows" for="tab-crRq0Rs">Windows</label><input type="radio" name="group-HuPdO" id="tab-5aYKzo6"><label data-title="Linux" for="tab-5aYKzo6">Linux</label></div><div class="blocks"><div class="language-text vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/Library/Application Support/Antigravity/User/globalStorage/state.vscdb</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%APPDATA%\\Antigravity\\User\\globalStorage\\state.vscdb</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.config/Antigravity/User/globalStorage/state.vscdb</span></span></code></pre></div></div></div><p><strong>次のように表示されます</strong>：</p><ul><li>インポート成功後、このアカウントは Manager の「現在のアカウント」に自動的に設定されます</li><li>システムは自動的にクォータ更新を 1 回トリガーします</li></ul><h3 id="ステップ-4-v1-データディレクトリから移行する-旧バージョンインポート" tabindex="-1">ステップ 4：V1 データディレクトリから移行する（旧バージョンインポート） <a class="header-anchor" href="#ステップ-4-v1-データディレクトリから移行する-旧バージョンインポート" aria-label="Permalink to &quot;ステップ 4：V1 データディレクトリから移行する（旧バージョンインポート）&quot;">​</a></h3><p><strong>なぜ</strong> 以前 V1/スクリプト版を使用していた場合、Manager は古いデータディレクトリを直接スキャンし、インポートを試みることができます。</p><p>操作：<code>Import</code> タブで、「Import V1」をクリックします。</p><p>ホームディレクトリの下でこのパス（およびその中のインデックスファイル）を検索します：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.antigravity-agent/</span></span>
<span class="line"><span>  - antigravity_accounts.json</span></span>
<span class="line"><span>  - accounts.json</span></span></code></pre></div><p><strong>次のように表示されます</strong>：インポート完了後、アカウントがリストに表示されます。インデックスファイルが見つからない場合、バックエンドはエラー <code>V1 account data file not found</code> を返します。</p><h3 id="ステップ-5-オプション-「現在アカウントの自動同期」を有効にする" tabindex="-1">ステップ 5（オプション）：「現在アカウントの自動同期」を有効にする <a class="header-anchor" href="#ステップ-5-オプション-「現在アカウントの自動同期」を有効にする" aria-label="Permalink to &quot;ステップ 5（オプション）：「現在アカウントの自動同期」を有効にする&quot;">​</a></h3><p><strong>なぜ</strong> Antigravity/IDE でログインアカウントを切り替える際、Manager は固定間隔で DB 内の refresh_token が変更されたかどうかを検出し、変更があれば自動的にインポートできます。</p><p>操作：<code>Settings</code> に入り、<code>auto_sync</code> を有効にし、<code>sync_interval</code> を設定します（単位：秒）。</p><p><strong>次のように表示されます</strong>：有効にすると、即座に 1 回の同期が実行されます。その後、間隔に従って定期的に実行されます。DB 内の refresh_token が現在のアカウントと同じ場合、スキップされ、重複インポートされません。</p><h2 id="チェックポイント-✅" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h2><ul><li><code>Accounts</code> リストにインポートされたアカウントが表示されます</li><li>「現在のアカウント」が期待するものに切り替わっているのが確認できます（DB インポートは自動的に現在に設定します）</li><li>Proxy を起動すると、新しくインポートされたアカウントが正常にリクエストに使用できます（実際の呼び出し結果に基づきます）</li></ul><h2 id="トラブルシューティング" tabindex="-1">トラブルシューティング <a class="header-anchor" href="#トラブルシューティング" aria-label="Permalink to &quot;トラブルシューティング&quot;">​</a></h2><table tabindex="0"><thead><tr><th>シナリオ</th><th>間違ったやり方（❌）</th><th>推奨されるやり方（✓）</th></tr></thead><tbody><tr><td>バックアップファイルのセキュリティ</td><td>エクスポートされた JSON を通常の設定ファイルとして手放しに配布する</td><td>JSON をパスワードとして扱い、伝播範囲を最小限にし、パブリックネットワークへの露出を避ける</td></tr><tr><td>JSON インポート失敗</td><td>JSON が配列ではない、または refresh_token に <code>1//</code> 接頭辞がない</td><td>プロジェクトからエクスポートされた JSON をテンプレートとして使用し、フィールド名と構造を一致させる</td></tr><tr><td>DB インポートでデータが見つからない</td><td>Antigravity がログインしていない、または DB に <code>jetskiStateSync.agentManagerInitState</code> が不足している</td><td>最初に Antigravity/IDE がログインしていることを確認し、インポートを再試行する。必要に応じて Custom DB で正しいファイルを選択する</td></tr><tr><td>V1 インポート後、アカウントが使用不可</td><td>古い refresh_token が無効</td><td>そのアカウントを削除し、OAuth/新しい refresh_token で再度追加する（エラー通知に基づく）</td></tr><tr><td>auto_sync が頻繁すぎる</td><td><code>sync_interval</code> を小さく設定し、頻繁に DB をスキャンする</td><td>「状態追従」とみなし、受け入れ可能な頻度に間隔を設定する</td></tr></tbody></table><h2 id="このレッスンのまとめ" tabindex="-1">このレッスンのまとめ <a class="header-anchor" href="#このレッスンのまとめ" aria-label="Permalink to &quot;このレッスンのまとめ&quot;">​</a></h2><ul><li>JSON エクスポート/インポートは最も制御可能な移行方法：バックアップファイルには <code>email + refresh_token</code> のみが含まれる</li><li>DB インポートは「Antigravity/IDE の現在ログインアカウントを基準とする」場合に適しており、自動的に Manager の現在のアカウントに設定される</li><li>V1 インポートは <code>~/.antigravity-agent</code> をスキャンし、複数の旧形式と互換性がある</li><li>auto_sync は refresh_token を比較し、同じ場合はスキップし、重複インポートしない</li></ul><h2 id="次のレッスン予告" tabindex="-1">次のレッスン予告 <a class="header-anchor" href="#次のレッスン予告" aria-label="Permalink to &quot;次のレッスン予告&quot;">​</a></h2><blockquote><p>次のレッスンでは、「移行後のアカウントプール」を実際に使用します：<strong><a href="./../proxy-and-first-client/">ローカルリバースプロキシを起動し、最初のクライアントを接続する（/healthz + SDK 設定）</a></strong>。</p><p>学びます：</p><ul><li>Proxy を起動/停止し、<code>/healthz</code> で最小限の検証を行う方法</li><li>SDK/クライアントで Base URL を設定する方法</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を表示</strong></summary><blockquote><p>更新日時：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>Accounts エクスポート/インポート JSON（<code>save_text_file</code> / <code>read_text_file</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Accounts.tsx#L458-L578" target="_blank" rel="noreferrer"><code>src/pages/Accounts.tsx</code></a></td><td>458-578</td></tr><tr><td>Dashboard でアカウント JSON をエクスポート</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Dashboard.tsx#L113-L148" target="_blank" rel="noreferrer"><code>src/pages/Dashboard.tsx</code></a></td><td>113-148</td></tr><tr><td>Import タブ：DB インポート / Custom DB / V1 インポートボタン</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L491-L539" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>491-539</td></tr><tr><td>アカウント追加：フロントエンド email を無視、refresh_token を使用して実際のメールアドレスを取得し、自動クォータ更新、Proxy ホットリロード</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L19-L60" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>19-60</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>DB インポート：<code>state.vscdb</code> から refresh_token を抽出（ItemTable + base64 + protobuf）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/migration.rs#L192-L267" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/migration.rs</code></a></td><td>192-267</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>DB インポート後、自動的に「現在のアカウント」に設定し、クォータを更新</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L495-L511" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>495-511</td></tr><tr><td>auto_sync：refresh_token を比較し、同じ場合はスキップ、変更がある場合は DB インポートをトリガー</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L532-L564" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>532-564</td></tr><tr><td>フロントエンドバックグラウンドタスク：<code>sync_interval</code> に従って定期的に <code>syncAccountFromDb()</code> を呼び出し</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/common/BackgroundTaskRunner.tsx#L43-L72" target="_blank" rel="noreferrer"><code>src/components/common/BackgroundTaskRunner.tsx</code></a></td><td>43-72</td></tr></tbody></table></details>`,61)])])}const g=a(r,[["render",o]]);export{u as __pageData,g as default};
